_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec3 _fx_vol = vec3( audioLowSmooth, audioMidSmooth, audioHighSmooth );

  for ( int i = 0; i < 3; i++ )
  {
    _fx_vol[i] = ( min( 1., _fx_vol[i] ) * 1.7 )
                 + max( .0, _fx_vol[i] - 1. );
    _fx_vol[i] = min( 4.1, _fx_vol[i] );
  }

  _fx_vol += rot_f3[0] * .5;
  _fx_vol *= .07;
  _fx_vol *= 0.9;
  _fx_vol += 0.02;

  float _fx_decay = .82 + ( ( uFps - 85 ) * .002 );;
  float _fx_rad = length( vec2(
    ( vUv.x - .5 ) * uAspect.x,
    ( vUv.y - .5 ) * uAspect.y ) );
  float _fx_zoom = max( 0, _fx_rad - .12 ) * ( .028 + ( ( 85 - uFps ) * .0004 ) );

  _fx_zoom *= 1. + max( 0, ( cos( vAngle * 4 ) * .7 ) - .4 );

  vec2 _fx_prevframe = vUvOriginal;
  _fx_prevframe.x += ( _fx_zoom * uAspect.y ) * ( vUvOriginal.x > .5 ? -1. : 1. );
  _fx_prevframe.y += ( _fx_zoom * uAspect.x ) * ( vUvOriginal.y > .5 ? -1. : 1. );

  ret = texture( sampler_main, _fx_prevframe ) * _fx_decay;

  float _fx_width = ( _fx_rad * .04 ) + ( uRms * .004 );
  float _fx_spinmult = 600.;

  for ( int i = 0; i < 3; i++ )
    if ( _fx_rad > ( _fx_vol[i] - _fx_width )
      && _fx_rad < ( _fx_vol[i] + _fx_width ) )
      ret[i] = max( ret[i],
        ( 2. * _fx_vol[i] ) *
        + ( 3. * cos( vAngle + ( _fx_spinmult * _fx_vol[i] ) ) )
     );

  vec3 _fx_glow_intens = vec3( 1.6, 1.0, 1.3 );
  vec3 _fx_glow_vol = ( _fx_vol * 1.3 ) * max( 0, _fx_rad - .2 );

  for ( int i = 0; i < 3; i++ )
    ret[i] = max( ret[i], _fx_glow_vol[i] * _fx_glow_intens[i] );

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  vec2 _fx_blur3_uv = vUv;

  _fx_blur3_uv.x -= .005;
  _fx_blur3_uv.y -= .007;

  ret = max( ret, GetBlur1( vUv ) * ( 1.0 - vRadius ) );
  ret = max( ret, GetBlur3( _fx_blur3_uv ) * min( vRadius * 6, 1.3 ) );
  ret = max( ret, texture( sampler_main, vUv ) * min( vRadius * 5, 1 ) * max( 0, 2 - ( vRadius * 2.7 ) ) );

  float letterb = .025;
  ret *= vUv.y > letterb && vUv.y < ( 1. - letterb ) ? 1. : 0.;

  fragColor = ret;
}
